          <Scissors size={32} className="text-accent mx-auto mb-4" />
          <h2 className="font-serif font-semibold text-[2rem] leading-[1.2] mb-2">Create Account</h2>
          <p className="text-gray-400">Join CutPro for premium grooming</p>
