import React, { useEffect, useState } from 'react';
import axios from 'axios';
import AdminLayout from '../../components/admin/AdminLayout';
import { Tag, Percent, IndianRupee, Check } from 'lucide-react';

interface Service {
  _id: string;
  name: string;
  price: number;
  category: string;
  hasOffer: boolean;
  discountPrice?: number;
  isActive: boolean;
}

const AdminOffers: React.FC = () => {
  const [services, setServices] = useState<Service[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);

  const fetchServices = async () => {
    try {
      const { data } = await axios.get('/services');
      setServices(data.data);
    } catch (error) {
      console.error('Failed to fetch services', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchServices(); }, []);

  const toggleOffer = async (service: Service) => {
    setSaving(service._id);
    try {
      await axios.put(`/admin/services/${service._id}`, {
        hasOffer: !service.hasOffer,
        discountPrice: service.hasOffer ? undefined : Math.round(service.price * 0.8)
      }, { withCredentials: true });
      fetchServices();
    } catch (error) {
      console.error('Failed to update offer', error);
    } finally {
      setSaving(null);
    }
  };

  const updateDiscountPrice = async (id: string, discountPrice: number) => {
    setSaving(id);
    try {
      await axios.put(`/admin/services/${id}`, { discountPrice }, { withCredentials: true });
      fetchServices();
    } catch (error) {
      console.error('Failed to update discount', error);
    } finally {
      setSaving(null);
    }
  };

  const activeOffers = services.filter(s => s.hasOffer);
  const noOffers = services.filter(s => !s.hasOffer && s.isActive);

  return (
    <AdminLayout>
      {/* Active Offers */}
      <div className="mb-8">
        <div className="flex items-center gap-2 mb-4">
          <Tag size={18} className="text-accent" />
          <h3 className="text-white text-[1.1rem] font-semibold">Active Offers ({activeOffers.length})</h3>
        </div>

        {activeOffers.length === 0 ? (
          <div className="bg-white/[0.02] border border-white/[0.06] rounded-xl p-8 text-center">
            <Tag size={40} className="mx-auto mb-3 opacity-20 text-gray-500" />
            <p className="text-gray-500 text-[0.9rem]">No active offers. Enable a discount on any service below.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
            {activeOffers.map(service => (
              <div key={service._id} className="bg-accent/[0.04] border border-accent/20 rounded-xl p-5 relative">
                <div className="absolute top-3 right-3">
                  <span className="px-2 py-0.5 text-[0.68rem] font-bold uppercase bg-accent/10 text-accent rounded">
                    {service.discountPrice ? Math.round(((service.price - service.discountPrice) / service.price) * 100) : 0}% OFF
                  </span>
                </div>
                <p className="text-white font-medium text-[1rem] mb-1">{service.name}</p>
                <p className="text-gray-500 text-[0.78rem] mb-3">{service.category}</p>

                <div className="flex items-baseline gap-2 mb-4">
                  <span className="text-accent font-bold text-[1.4rem]">Γé╣{service.discountPrice}</span>
                  <span className="text-gray-500 line-through text-[0.9rem]">Γé╣{service.price}</span>
                  <span className="text-green-400 text-[0.78rem] ml-1">Save Γé╣{service.price - (service.discountPrice || 0)}</span>
                </div>

                {/* Edit discount price inline */}
                <div className="flex items-center gap-2 mb-4">
                  <label className="text-gray-400 text-[0.75rem]">Offer Price:</label>
                  <input
                    type="number"
                    min={0}
                    max={service.price}
                    defaultValue={service.discountPrice}
                    onBlur={e => {
                      const val = parseInt(e.target.value) || 0;
                      if (val !== service.discountPrice) updateDiscountPrice(service._id, val);
                    }}
                    className="w-24 bg-white/[0.06] border border-white/[0.1] text-white py-1.5 px-3 rounded text-[0.85rem] outline-none focus:border-accent/40"
                  />
                </div>

                <button
                  onClick={() => toggleOffer(service)}
                  disabled={saving === service._id}
                  className="w-full py-2 rounded-lg text-[0.8rem] font-medium text-red-400 border border-red-500/20 hover:bg-red-500/10 transition-all"
                >
                  {saving === service._id ? 'Updating...' : 'Remove Offer'}
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Services without offers */}
      <div>
        <div className="flex items-center gap-2 mb-4">
          <Percent size={18} className="text-gray-400" />
          <h3 className="text-white text-[1.1rem] font-semibold">Add Discount to Services</h3>
        </div>

        {loading ? (
          <div className="flex items-center justify-center h-[30vh]"><div className="spinner" /></div>
        ) : noOffers.length === 0 ? (
          <p className="text-gray-500 text-[0.9rem]">All services already have offers.</p>
        ) : (
          <div className="bg-white/[0.02] border border-white/[0.06] rounded-xl overflow-hidden">
            <table className="w-full text-left text-[0.88rem]">
              <thead>
                <tr className="bg-white/[0.02] border-b border-white/[0.06] text-gray-500 text-[0.75rem] uppercase tracking-wider">
                  <th className="py-3 px-5 font-medium">Service</th>
                  <th className="py-3 px-5 font-medium">Category</th>
                  <th className="py-3 px-5 font-medium">Current Price</th>
                  <th className="py-3 px-5 font-medium text-right">Action</th>
                </tr>
              </thead>
              <tbody>
                {noOffers.map(service => (
                  <tr key={service._id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                    <td className="py-3 px-5 text-white font-medium">{service.name}</td>
                    <td className="py-3 px-5">
                      <span className="px-2 py-0.5 text-[0.7rem] font-medium bg-white/[0.05] text-gray-300 rounded">{service.category}</span>
                    </td>
                    <td className="py-3 px-5 text-white">Γé╣{service.price}</td>
                    <td className="py-3 px-5 text-right">
                      <button
                        onClick={() => toggleOffer(service)}
                        disabled={saving === service._id}
                        className="px-3 py-1.5 rounded-lg text-[0.78rem] font-medium bg-accent/10 text-accent border border-accent/20 hover:bg-accent/20 transition-all disabled:opacity-50"
                      >
                        {saving === service._id ? 'Enabling...' : 'Enable Offer'}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </AdminLayout>
  );
};

export default AdminOffers;

import React, { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { Lock, ShieldCheck, CheckCircle } from 'lucide-react';

const AdminResetPassword: React.FC = () => {
  const { token } = useParams<{ token: string }>();
  const navigate = useNavigate();

  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters long');
      return;
    }

    setLoading(true);

    try {
      await axios.put(`/admin/reset-password/${token}`, { password });
      setSuccess(true);
      setTimeout(() => {
        navigate('/admin/login');
      }, 3000);
    } catch (err: any) {
      setError(err.response?.data?.message || 'Failed to reset password. The link might be expired or invalid.');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4 relative overflow-hidden bg-[#0B0E14]">
        <div className="absolute w-[500px] h-[500px] bg-[radial-gradient(circle,rgba(0,255,100,0.04),transparent_70%)] top-[20%] left-[10%] rounded-full blur-[120px]" />
        <div className="w-full max-w-[420px] bg-white/[0.03] border border-white/[0.08] rounded-2xl p-10 text-center relative z-10">
          <CheckCircle size={50} className="text-green-500 mx-auto mb-5" />
          <h2 className="text-white text-[1.4rem] font-semibold mb-2">Password Reset!</h2>
          <p className="text-gray-400 text-[0.95rem] mb-6">
            Your password has been changed successfully. You will be redirected to the login page momentarily.
          </p>
          <Link to="/admin/login" className="text-accent hover:underline text-[0.9rem]">
            Click here to log in now
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-4 relative overflow-hidden bg-[#0B0E14]">
      {/* Subtle background effects */}
      <div className="absolute w-[500px] h-[500px] bg-[radial-gradient(circle,rgba(0,229,255,0.04),transparent_70%)] top-[20%] left-[10%] rounded-full blur-[120px]" />

      <div className="w-full max-w-[420px] relative z-10">
        <div className="text-center mb-8">
          <div className="w-14 h-14 mx-auto mb-4 bg-accent/10 border border-accent/20 rounded-2xl flex items-center justify-center">
            <ShieldCheck size={26} className="text-accent" />
          </div>
          <h1 className="font-serif text-[1.8rem] font-bold text-white tracking-wide mb-1">Reset Password</h1>
          <p className="text-gray-500 text-[0.88rem]">Enter your new secure password</p>
        </div>

        <div className="bg-white/[0.03] border border-white/[0.08] rounded-2xl p-8">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 py-3 px-4 rounded-lg mb-5 text-[0.85rem] text-center">
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <div>
              <label className="text-gray-400 text-[0.75rem] font-medium uppercase tracking-wider block mb-1.5">New Password</label>
              <div className="relative">
                <Lock size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-600" />
                <input
                  type="password"
                  placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                  required
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  className="w-full bg-white/[0.04] border border-white/[0.08] text-white py-3 pr-4 pl-10 rounded-lg text-[0.9rem] outline-none focus:border-accent/40 transition-colors"
                />
              </div>
            </div>

            <div>
              <label className="text-gray-400 text-[0.75rem] font-medium uppercase tracking-wider block mb-1.5">Confirm Password</label>
              <div className="relative">
                <Lock size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-600" />
                <input
                  type="password"
                  placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                  required
                  value={confirmPassword}
                  onChange={e => setConfirmPassword(e.target.value)}
                  className="w-full bg-white/[0.04] border border-white/[0.08] text-white py-3 pr-4 pl-10 rounded-lg text-[0.9rem] outline-none focus:border-accent/40 transition-colors"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="flex items-center justify-center gap-2 w-full py-3 mt-2 rounded-lg text-[0.88rem] font-semibold bg-accent text-black hover:bg-accent/90 transition-colors disabled:opacity-50"
